module RefModule (CLK, RESET, Q);
input CLK;
input RESET;
output reg [2:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (RESET) begin
        Q <= 3'b000;
    end
    else begin
        Q <= Q + 1;
    end
end

endmodule
